import axios from 'axios';

const API_BASE_URL = process.env.REACT_APP_API_URL; 

class ProductService {
    // Sửa thành: /admin/products/products
    async getAllProducts() {
        const token = localStorage.getItem("token");
        const res = await axios.get(`${API_BASE_URL}/admin/products/products`, {
            headers: { Authorization: `Bearer ${token}` }
        });
        return res.data;
    }

    // Sửa thành: /admin/categories/category
    async getAllCategories() {
        const token = localStorage.getItem("token");
        const res = await axios.get(`${API_BASE_URL}/admin/categories/category`, {
            headers: { Authorization: `Bearer ${token}` }
        });
        return res.data;
    }

    // Sửa các endpoint CRUD (Thêm/Sửa/Xóa)
    async saveProduct(productData, isEdit) {
        const token = localStorage.getItem("token");
        // Endpoint Backend của sếp là: /admin/products
        const url = `${API_BASE_URL}/admin/products${isEdit ? '/' + productData.product_id : ''}`;
        
        const method = isEdit ? "put" : "post";
        return await axios[method](url, productData, {
            headers: { Authorization: `Bearer ${token}` }
        });
    }

    async deleteProduct(id) {
        const token = localStorage.getItem("token");
        // Endpoint Backend của sếp là: /admin/products/:id
        return await axios.delete(`${API_BASE_URL}/admin/products/${id}`, {
            headers: { Authorization: `Bearer ${token}` }
        });
    }
}

export default new ProductService();
